/*
 * atan() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly atan  (test_atan_opt.elf)
 *   2. Linked with toolchain's default atan       (test_atan_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static void emit(double x)
{
    double r = atan(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0);
    emit(-0.0);

    /* NaN */
    emit_u(0x7ff8000000000000ULL); /* qNaN */
    emit_u(0x7ff0000000000001ULL); /* sNaN */
    emit_u(0xfff8000000000000ULL); /* -NaN */

    /* Infinity */
    emit_u(0x7ff0000000000000ULL); /* +Inf */
    emit_u(0xfff0000000000000ULL); /* -Inf */
}

/* 2. Tiny values: atan(x) ~ x */
static void test_tiny(void)
{
    emit_u(0x0000000000000001ULL); /* min denorm */
    emit_u(0x8000000000000001ULL);
    emit_u(0x0008000000000000ULL); /* mid denorm */
    emit_u(0x8008000000000000ULL);
    emit_u(0x000fffffffffffffULL); /* max denorm */
    emit_u(0x800fffffffffffffULL);
    emit(DBL_MIN);
    emit(-DBL_MIN);
    emit(1.0e-200);
    emit(-1.0e-200);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    emit(0.0);
    emit(1.0 / sqrt(3.0));
    emit(1.0);
    emit(sqrt(3.0));
    emit(-1.0 / sqrt(3.0));
    emit(-1.0);
    emit(-sqrt(3.0));
}

/* 4. Large arguments */
static void test_large(void)
{
    double vals[] = {
        10.0, 100.0, 1000.0, 1.0e10, 1.0e20,
        -10.0, -1000.0, -1.0e10, -1.0e20,
        DBL_MAX, -DBL_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Normal range values */
static void test_quadrant(void)
{
    double vals[] = { -10.0, -2.0, -1.0, -0.5, -0.1, 0.0, 0.1, 0.5, 1.0, 2.0, 10.0 };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 6. Hard values near asymptotes */
static void test_hard(void)
{
    double cases[] = {
        u2d(0x3fe921fb54442d18ULL), /* 0.7853981... (pi/4 normalized) */
        u2d(0x3ff0000000000000ULL), /* 1.0 */
        u2d(0x4024000000000000ULL), /* 10.0 */
        u2d(0x4059000000000000ULL), /* 100.0 */
        u2d(0x408f400000000000ULL), /* 1000.0 */
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        emit(-cases[i]);
    }
}

/* 7. Sweep [-100, 100] in 200 steps */
static void test_sweep(void)
{
    int nsteps = 200;
    double step = 200.0 / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(-100.0 + (double)i * step);
}

/* 8. Sample [0, 1] every 4503599627370496 ULP (~200 cases) */
static void test_exhaustive_small(void)
{
    uint64_t end = 0x3ff0000000000000ULL; /* 1.0 */
    for (uint64_t b = 0; b <= end; b += 4503599627370496ULL)
        emit_u(b);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    double lo = -10.0;
    double hi =  10.0;
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_quadrant();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
    return 0;
}

