    52→    emit(-0.0, 0.5);
    53→    emit(0.0, 2.0);
    54→
    55→    /* Base = 1 (identity) */
    56→    emit(1.0, 0.0);
    57→    emit(1.0, 2.0);
    58→    emit(1.0, -2.0);
    59→    emit(1.0, 100.0);
    60→
    61→    /* Exponent = 0 (result always 1) */
    62→    emit(2.0, 0.0);
    63→    emit(10.0, 0.0);
    64→    emit(-5.0, 0.0);
    65→
    66→    /* NaN and Inf cases */
