    92→    /* Base and exponent pairs: (3,2)=9, (4,2)=16, (5,2)=25 (3-4-5 triple squared) */
    93→    emit(3.0, 2.0);   /* 9 */
    94→    emit(4.0, 2.0);   /* 16 */
    95→    emit(5.0, 2.0);   /* 25 (sqrt(9+16)) */
