   176→/* 7. Sweep base [0.5, 10] and exponent [0, 5] */
   177→static void test_sweep(void)
   178→{
   179→    int nbase = 50;
   180→    int nexp = 50;
   181→
   182→    for (int i = 0; i <= nbase; i++) {
   183→        double base = 0.5 + (10.0 - 0.5) * (double)i / (double)nbase;
   184→        for (int j = 0; j <= nexp; j++) {
   185→            double exp = (double)j * 5.0 / (double)nexp;
   186→            emit(base, exp);
   187→        }
   188→    }
   189→}
   190→
   191→/* 8. Sample critical range with ULP granularity */
   192→static void test_exhaustive_small(void)
   193→{
   194→    /* Base in [1.0, 2.0], exponent in [0, 1] */
   195→    uint64_t base_start = 0x3ff0000000000000ULL; /* 1.0 */
   196→    uint64_t base_end = 0x4000000000000000ULL;   /* 2.0 */
   197→    uint64_t exp_start = 0x0000000000000000ULL;  /* 0.0 */
   198→    uint64_t exp_end = 0x3ff0000000000000ULL;    /* 1.0 */
   199→    int nsteps = 16;
   200→
   201→    for (int i = 0; i <= nsteps; i++) {
   202→        double base = u2d(base_start) + (u2d(base_end) - u2d(base_start)) * (double)i / (double)nsteps;
   203→        for (int j = 0; j <= nsteps; j++) {
   204→            double exp = u2d(exp_start) + (u2d(exp_end) - u2d(exp_start)) * (double)j / (double)nsteps;
   205→            emit(base, exp);
   206→        }
   207→    }
   208→}
   209→
   210→/* 9. Random sweep: 15x20 grid = 300 cases */
   211→static void test_random_300(void)
   212→{
   213→    int nx = 15, ny = 20;
   214→    for (int i = 0; i < nx; i++) {
   215→        double x = 0.5 + 9.5 * (double)i / (double)(nx - 1);
   216→        for (int j = 0; j < ny; j++) {
   217→            double y = -3.0 + 6.0 * (double)j / (double)(ny - 1);
   218→            emit(x, y);
   219→        }
   220→    }
   221→}
   222→
   223→/* ------------------------------------------------------------------ */
   224→
   225→int main(void)
   226→{
   227→    test_special();
   228→    test_tiny();
   229→    test_known();
   230→    test_large();
   231→    test_exponent_range();
   232→    test_hard();
   233→    test_sweep();
   234→    test_exhaustive_small();
   235→    test_random_300();
   236→    return 0;
   237→}
