   132→    for (int i = 0; i < n; i++)
   133→        emit(cases[i]);
   134→}
   135→
   136→/* 7. Sweep [-4*pi, 4*pi] in 200 steps */
   137→static void test_sweep(void)
   138→{
   139→    float hi = 4.0f * 3.14159265358979323846f;
   140→    int nsteps = 200;
   141→    float step = (2.0f * hi) / (float)nsteps;
   142→
   143→    for (int i = 0; i <= nsteps; i++)
   144→        emit(-hi + (float)i * step);
   145→}
   146→
   147→/* 8. Sample [-1, 1] every 4194304 ULP (~500 cases) */
   148→static void test_exhaustive_small(void)
   149→{
   150→    uint32_t start = 0xbf800000u; /* -1.0 */
   151→    uint32_t end = 0x3f800000u;   /* 1.0 */
   152→
   153→    for (uint32_t b = start; b <= end; b += 2097152)
   154→        emit_u(b);
   155→}
   156→
   157→/* 9. Random sweep: 300 evenly spaced inputs */
   158→static void test_random_300(void)
   159→{
   160→    float lo = -100.0f;
   161→    float hi =  100.0f;
   162→    int n = 300;
   163→    for (int i = 0; i < n; i++) {
   164→        float x = lo + (hi - lo) * (float)i / (float)(n - 1);
   165→        emit(x);
   166→    }
   167→}
