    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→static inline uint32_t f2u(float f)
    16→{
    17→    union { float f; uint32_t u; } x;
    18→    x.f = f;
    19→    return x.u;
    20→}
    21→
    22→static inline float u2f(uint32_t u)
    23→{
    24→    union { float f; uint32_t u; } x;
    25→    x.u = u;
    26→    return x.f;
    27→}
    28→
    29→static void emit(float x)
    30→{
    31→    int ex;
    32→    float r = frexpf(x, &ex);
    33→    printf("%08lx %08lx %d\n",
    34→           (unsigned long)f2u(x), (unsigned long)f2u(r), ex);
    35→}
    36→
    37→static void emit_u(uint32_t bits)
    38→{
    39→    emit(u2f(bits));
    40→}
    41→
    42→/* ------------------------------------------------------------------ */
    43→/* Test points                                                         */
    44→/* ------------------------------------------------------------------ */
    45→
    46→/* 1. Special values */
    47→static void test_special(void)
    48→{
    49→    /* Zeros */
    50→    emit(0.0f);
    51→    emit(-0.0f);
    52→
    53→    /* NaN */
    54→    emit_u(0x7fc00000u); /* qNaN */
    55→    emit_u(0x7f800001u); /* sNaN */
    56→    emit_u(0xffc00000u); /* -NaN */
    57→
    58→    /* Infinity */
    59→    emit_u(0x7f800000u); /* +Inf */
    60→    emit_u(0xff800000u); /* -Inf */
    61→}
    62→
    63→/* 2. Tiny values: denormals */
    64→static void test_tiny(void)
    65→{
    66→    emit_u(0x00000001u); /* min denorm */
    67→    emit_u(0x80000001u);
    68→    emit_u(0x00400000u); /* mid denorm */
    69→    emit_u(0x80400000u);
    70→    emit_u(0x007fffffu); /* max denorm */
    71→    emit_u(0x807fffffu);
    72→    emit(FLT_MIN);
    73→    emit(-FLT_MIN);
    74→    emit(1.0e-30f);
    75→    emit(-1.0e-30f);
    76→}
    77→
    78→/* 3. Known values with specific exponents */
    79→static void test_known(void)
    80→{
    81→    float vals[] = {
    82→        0.5f, -0.5f,      /* exp = 0 */
    83→        1.0f, -1.0f,      /* exp = 1 */
    84→        1.5f, -1.5f,      /* exp = 1 */
    85→        2.0f, -2.0f,      /* exp = 2 */
    86→        3.14159265f, -3.14159265f,
    87→        100.0f, -100.0f,
    88→    };
    89→    int n = sizeof(vals) / sizeof(vals[0]);
    90→    for (int i = 0; i < n; i++)
    91→        emit(vals[i]);
    92→}
    93→
    94→/* 4. Large arguments */
    95→static void test_large(void)
    96→{
    97→    float vals[] = {
    98→        1000.0f, -1000.0f,
    99→        1.0e10f, -1.0e10f,
   100→        1.0e20f, -1.0e20f,
   101→        FLT_MAX, -FLT_MAX,
   102→    };
   103→    int n = sizeof(vals) / sizeof(vals[0]);
   104→    for (int i = 0; i < n; i++)
   105→        emit(vals[i]);
   106→}
   107→
   108→/* 5. Powers of 2 (pure exponent) */
   109→static void test_powers_of_2(void)
   110→{
   111→    for (int i = -10; i <= 10; i++) {
   112→        float v = powf(2.0f, (float)i);
   113→        emit(v);
   114→        emit(-v);
   115→    }
   116→}
   117→
   118→/* 6. Worst-case mantissa values */
   119→static void test_hard(void)
   120→{
   121→    float cases[] = {
   122→        0.125f, 0.25f, 0.375f, 0.5f, 0.625f, 0.75f, 0.875f, 0.999f,
   123→        1.001f, 1.125f, 1.25f, 1.5f, 1.75f, 1.999f,
   124→    };
   125→    int n = sizeof(cases) / sizeof(cases[0]);
   126→    for (int i = 0; i < n; i++) {
   127→        emit(cases[i]);
   128→        emit(-cases[i]);
   129→    }
   130→}
   131→
   132→/* 7. Sweep [0.5, 2) mantissa range with integer base exponents */
   133→static void test_sweep(void)
   134→{
   135→    float lo = 0.5f, hi = 2.0f;
   136→    int nsteps = 100;
   137→    float step = (hi - lo) / (float)nsteps;
   138→
   139→    for (int i = 0; i <= nsteps; i++)
   140→        emit(lo + (float)i * step);
   141→
   142→    /* Negative */
   143→    for (int i = 0; i <= nsteps; i++)
   144→        emit(-(lo + (float)i * step));
   145→}
   146→
   147→/* 8. Sample [0.5, 1] every 2097152 ULP (~250 cases) */
   148→static void test_exhaustive_small(void)
   149→{
   150→    uint32_t start = 0x3f000000u; /* 0.5 */
   151→    uint32_t end = 0x3f800000u;   /* 1.0 */
   152→    for (uint32_t b = start; b <= end; b += 2097152)
   153→        emit_u(b);
   154→}
   155→
   156→/* 9. Random sweep: 300 evenly spaced inputs */
   157→static void test_random_300(void)
   158→{
   159→    float lo = -100.0f;
   160→    float hi =  100.0f;
   161→    int n = 300;
   162→    for (int i = 0; i < n; i++) {
   163→        float x = lo + (hi - lo) * (float)i / (float)(n - 1);
   164→        emit(x);
   165→    }
   166→}
   167→
   168→/* ------------------------------------------------------------------ */
   169→
   170→int main(void)
   171→{
   172→    test_special();
   173→    test_tiny();
   174→    test_known();
   175→    test_large();
   176→    test_powers_of_2();
   177→    test_hard();
   178→    test_sweep();
   179→    test_exhaustive_small();
   180→    test_random_300();
   181→    return 0;
   182→}
