    53→    emit_u(0x7ff0000000000001ULL); /* sNaN */
    54→    emit_u(0xfff8000000000000ULL); /* -NaN */
    55→
    56→    /* Infinity */
    57→    emit_u(0x7ff0000000000000ULL); /* +Inf (log1p(Inf) = Inf) */
    58→    emit_u(0xfff0000000000000ULL); /* -Inf (log1p(-Inf) = NaN) */
    59→
    60→    /* Boundary: log1p(-1) = -Inf */
    61→    emit_u(0xbff0000000000000ULL); /* -1.0 */
    62→}
    63→
    64→/* 2. Tiny values: log1p(x) ~ x when x is tiny */
    65→static void test_tiny(void)
    66→{
    67→    emit_u(0x0000000000000001ULL); /* min denorm */
    68→    emit_u(0x8000000000000001ULL);
