}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(2.0f);
#else
    test_special_base();
    test_tiny();
    test_known();
    test_large();
    test_negative_base();
    test_hard();
    test_sweep_base();
    test_sweep_exp();
    test_random_300();
#endif
    return 0;
}

