/*
 * tanh() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly tanh  (test_tanh_opt.elf)
 *   2. Linked with toolchain's default tanh        (test_tanh_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static void emit(double x)
{
    double r = tanh(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0);
    emit(-0.0);

    /* NaN */
    emit_u(0x7ff8000000000000ULL); /* qNaN */
    emit_u(0x7ff0000000000001ULL); /* sNaN */
    emit_u(0xfff8000000000000ULL); /* -NaN */

    /* Infinity */
    emit_u(0x7ff0000000000000ULL); /* +Inf */
    emit_u(0xfff0000000000000ULL); /* -Inf */
}

/* 2. Tiny values: tanh(x) ~ x */
static void test_tiny(void)
{
    emit(1.0e-200);
    emit(-1.0e-200);
    emit(1.0e-100);
    emit(-1.0e-100);
    emit(DBL_MIN);
    emit(-DBL_MIN);
    emit(1.0e-20);
    emit(-1.0e-20);
    emit(1.0e-10);
    emit(-1.0e-10);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    double vals[] = {
        0.1, 0.5, 1.0, 2.0, 5.0, 10.0,
        -0.1, -0.5, -1.0, -2.0, -5.0, -10.0,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 4. Large arguments (saturation near ±4) */
static void test_large(void)
{
    double vals[] = {
        3.0, 4.0, 4.5, 5.0, 10.0, 50.0, 100.0, 500.0, 700.0, 1000.0,
        -3.0, -4.0, -4.5, -5.0, -10.0, -50.0, -100.0, -709.0, -1000.0,
        DBL_MAX, -DBL_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Saturation threshold values (near ±4) */
static void test_critical(void)
{
    double thresholds[] = {
        3.9, 4.0, 4.1,
        -3.9, -4.0, -4.1,
    };
    int n = sizeof(thresholds) / sizeof(thresholds[0]);
    for (int i = 0; i < n; i++)
        emit(thresholds[i]);
}

/* 6. Hardest cases near unit fractions */
static void test_hard(void)
{
    double cases[] = {
        0.5, 1.0, 1.5, 2.0, 2.5, 3.0, 3.5,
        0.25, 0.75, 1.25, 1.75, 2.25, 2.75,
        -0.5, -1.0, -1.5, -2.0, -2.5, -3.0, -3.5,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++)
        emit(cases[i]);
}

/* 7. Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
static void test_sweep(void)
{
    double hi = 10.0;
    int nsteps = 100;
    double step = hi / (double)nsteps;

    /* [0, 10] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-10, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* 8. Sample [0, 10] every ~0.05 (200 points) */
static void test_exhaustive_small(void)
{
    double hi = 10.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    double lo = -5.0;
    double hi =  5.0;
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}
