   183→    test_tiny();
   184→    test_known();
   185→    test_large();
   186→    test_boundaries();
   187→    test_hard();
   188→    test_sweep();
   189→    test_exhaustive_small();
   190→    test_random_300();
   191→    return 0;
   192→}
