/*
 * ceilf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly ceilf  (test_ceilf_opt.elf)
 *   2. Linked with toolchain's default ceilf        (test_ceilf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifndef EN_PERF
static void emit(float x)
{
    float r = ceilf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0f);
    emit(-0.0f);

    /* NaN */
    emit_u(0x7fc00000u); /* qNaN */
    emit_u(0x7f800001u); /* sNaN */
    emit_u(0xffc00000u); /* -NaN */

    /* Infinity */
    emit_u(0x7f800000u); /* +Inf */
    emit_u(0xff800000u); /* -Inf */
}

/* 2. Tiny values: ceil(x) ~ 1 for x > 0, 0 for x <= 0 */
static void test_tiny(void)
{
    emit_u(0x00000001u); /* min denorm */
    emit_u(0x80000001u);
    emit_u(0x00400000u); /* mid denorm */
    emit_u(0x80400000u);
    emit_u(0x007fffffu); /* max denorm */
    emit_u(0x807fffffu);
    emit(FLT_MIN);
    emit(-FLT_MIN);
    emit(1.0e-20f);
    emit(-1.0e-20f);
    emit(1.0e-10f);
    emit(-1.0e-10f);
}

/* 3. Integer boundaries with fractional offsets */
static void test_known(void)
{
    float vals[] = {
        -2.5f, -2.0f, -1.5f, -1.0f, -0.5f, 0.0f,
        0.5f, 1.0f, 1.5f, 2.0f, 2.5f,
        3.1f, 4.9f, 5.0f, 5.1f,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 4. Large integer and fractional values */
static void test_large(void)
{
    float vals[] = {
        10.0f, 10.1f, 10.9f,
        100.0f, 100.5f,
        1000.0f, 1000.1f,
        1.0e10f, 1.0e10f + 0.5f,
        -10.0f, -10.1f, -10.9f,
        -100.0f, -100.5f,
        FLT_MAX, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Boundaries with precise offsets */
static void test_boundaries(void)
{
    for (int i = 0; i < 10; i++) {
        float base = (float)i;
        emit(base - 0.5f);
        emit(base);
        emit(base + 0.5f);
    }

    for (int i = 0; i > -10; i--) {
        float base = (float)i;
        emit(base - 0.5f);
        emit(base);
        emit(base + 0.5f);
    }
}

/* 6. Worst-case argument values */
static void test_hard(void)
{
    float cases[] = {
        0.125f, 0.25f, 0.375f, 0.625f, 0.75f, 0.875f,
        u2f(0x3f490fdbu), /* pi/4 */
        u2f(0x3fc90fdbu), /* pi/2 */
        u2f(0x4049cbe4u), /* 3*pi/2 */
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        emit(-cases[i]);
    }
}

/* 7. Sweep [0, 10] in 200 steps */
static void test_sweep(void)
{
    float hi = 10.0f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    /* [0, 10] */
    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);

    /* [-10, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* 8. Sample [0, 1] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    float lo = -50.0f;
    float hi =  50.0f;
    int n = 300;
    for (int i = 0; i < n; i++) {
        float x = lo + (hi - lo) * (float)i / (float)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(float x)
{
    volatile float acc = 0.0f;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += ceilf(x+i);
    stopPFM;
    readResult();
    printf("perf %08lx: %08lx\n",
           (unsigned long)f2u(x),
           (unsigned long)f2u((float)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(1.5f);
#else
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_boundaries();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

