/*
 * fabs() test harness — prints (input_hex, output_hex) pairs.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static void emit(double x)
{
    double r = fabs(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* 1. Special values */
static void test_special(void)
{
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -NaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */
}

/* 2. Tiny values (denorms and near-zero) */
static void test_tiny(void)
{
    emit_u(0x0000000000000001ULL);  /* min denorm positive */
    emit_u(0x8000000000000001ULL);  /* min denorm negative */
    emit_u(0x000fffffffffffffULL);  /* max denorm positive */
    emit_u(0x800fffffffffffffULL);  /* max denorm negative */
    emit(DBL_MIN);
    emit(-DBL_MIN);
    emit(1.0e-200);
    emit(-1.0e-200);
}

/* 3. Small normal values */
static void test_small_normal(void)
{
    double vals[] = { -1.0e-100, -1.0e-50, -1.0e-10, 1.0e-100, 1.0e-50, 1.0e-10 };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 4. Medium values */
static void test_medium(void)
{
    double vals[] = { -5.0, -3.5, -2.0, -1.5, -0.5, 0.0, 0.5, 1.5, 2.0, 3.5, 5.0 };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Medium-large values */
static void test_medium_large(void)
{
    double vals[] = { -10.0, -100.0, -1000.0, 10.0, 100.0, 1000.0 };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 6. Large values */
static void test_large(void)
{
    emit(1.0e100);
    emit(-1.0e100);
    emit(1.0e200);
    emit(-1.0e200);
    emit(DBL_MAX);
    emit(-DBL_MAX);
}

/* 7. Sweep with fractional values */
static void test_sweep(void)
{
    for (double i = -5.0; i <= 5.0; i += 0.5)
        emit(i);
}

/* 8. Sample across exponent range */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fc0000000000000ULL, /* 0.125 */
        0x3fd0000000000000ULL, /* 0.25 */
        0x3fe0000000000000ULL, /* 0.5 */
        0x3fe8000000000000ULL, /* 0.75 */
        0x3ff0000000000000ULL, /* 1.0 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++) {
        emit_u(vals[i]);
        emit_u(vals[i] | 0x8000000000000000ULL);
    }
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    double lo = -100.0;
    double hi =  100.0;
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(double x)
{
    volatile double acc = 0.0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += fabs(x+i);
    stopPFM;
    readResult();
    printf("perf %016llx: %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u((double)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(1.5);
#else
    test_special();
    test_tiny();
    test_small_normal();
    test_medium();
    test_medium_large();
    test_large();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

