static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static void emit(double x, double y)
{
    double r = fmod(x, y);
    printf("%016llx %016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(y), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t x_bits, uint64_t y_bits)
{
    emit(u2d(x_bits), u2d(y_bits));
}

/* 1. Special values */
static void test_special(void)
{
    emit(0.0, 1.0);
    emit(-0.0, 1.0);
    emit(1.0, 0.0);
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* qNaN, 1.0 */
    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);  /* sNaN, 1.0 */
    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);  /* -NaN, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0, qNaN */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);  /* +Inf, 1.0 */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL);  /* -Inf, 1.0 */
    emit(1.0, INFINITY);
}

/* 2. Tiny values (denorms and near-zero) */
static void test_tiny(void)
{
    emit_u(0x0000000000000001ULL, 1.0);  /* min denorm */
    emit_u(0x800fffffffffffffULL, 1.0);  /* mid denorm */
    emit_u(0x000fffffffffffffULL, 1.0);  /* max denorm */
    emit(DBL_MIN, 1.0);
    emit(-DBL_MIN, 1.0);
    emit(1.0e-100, 1.0e-50);
    emit(1.0e-200, 1.0e-100);
}

/* 3. Basic cases */
static void test_basic(void)
{
    emit(5.0, 2.0);
    emit(5.5, 2.5);
    emit(-5.0, 2.0);
    emit(5.0, -2.0);
    emit(-5.0, -2.0);
    emit(1.5, 0.5);
    emit(3.0, 2.0);
    emit(10.0, 3.0);
}

/* 4. Known mathematical cases */
static void test_known(void)
{
    emit(7.0, 2.5);
    emit(22.0, 7.0);
    emit(100.0, 30.0);
    emit(355.0, 113.0);
    emit(-7.0, 2.5);
    emit(-22.0, 7.0);
}

/* 5. Large operands */
static void test_large(void)
{
    emit(1e100, 1e50);
    emit(1e200, 1e100);
    emit(DBL_MAX, 1e100);
    emit(-1e100, 1e50);
    emit(1e50, 1e100);
}

/* 6. Exact divisibility cases */
static void test_exact(void)
{
    emit(10.0, 5.0);   /* x = 2*y */
    emit(15.0, 5.0);   /* x = 3*y */
    emit(100.0, 10.0); /* x = 10*y */
    emit(-20.0, 4.0);  /* negative exact */
    emit(0.5, 0.5);    /* x = y */
}

/* 7. Sweep through various ratios */
static void test_sweep(void)
{
    double ratios[] = { 1.1, 1.5, 2.0, 2.5, 3.0, 3.5, 4.0, 10.0 };
    int n = sizeof(ratios) / sizeof(ratios[0]);
    for (int i = 0; i < n; i++) {
        emit(ratios[i] * 10.0, 3.0);
        emit(-ratios[i] * 10.0, 3.0);
    }
}

