{
    emit(u2f(bits), exp);
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    int exps[] = { 0, 1, -1, 10, -10 };
    int ne = sizeof(exps) / sizeof(exps[0]);

    /* Zeros with various exponents */
    for (int j = 0; j < ne; j++) {
        emit(0.0f, exps[j]);
        emit(-0.0f, exps[j]);
    }

    /* NaN */
    emit_u(0x7fc00000u, 5);   /* qNaN */
    emit_u(0x7f800001u, 5);   /* sNaN */
    emit_u(0xffc00000u, 5);   /* -NaN */

    /* Infinity */
    emit_u(0x7f800000u, 5);   /* +Inf */
    emit_u(0xff800000u, 5);   /* -Inf */
}

/* 2. Tiny mantissa values with various exponents */
static void test_tiny(void)
{
    int exps[] = { 0, 1, -1, 10, -10, 100, -100 };
    int ne = sizeof(exps) / sizeof(exps[0]);

    for (int j = 0; j < ne; j++) {
        emit_u(0x00000001u, exps[j]); /* min denorm */
        emit_u(0x80000001u, exps[j]);
        emit(FLT_MIN, exps[j]);
        emit(-FLT_MIN, exps[j]);
        emit(1.0e-30f, exps[j]);
        emit(-1.0e-30f, exps[j]);
    }
}

/* 3. Known values: normalize frexp output */
static void test_known(void)
{
    /* frexp returns mantissa in [0.5, 1) with matching exponent */
    float mantissas[] = { 0.5f, 0.75f, 1.0f, -0.5f, -0.75f, -1.0f };
    int exponents[] = { 0, 1, 2, 5, 10, -5, -10 };

    for (int i = 0; i < 6; i++) {
        for (int j = 0; j < 7; j++) {
            emit(mantissas[i], exponents[j]);
        }
    }
}

/* 4. Large exponents (overflow/underflow transitions) */
static void test_large_exp(void)
{
    float vals[] = { 0.5f, 1.0f, -1.0f, FLT_MAX };
    int exps[] = { 127, 126, -126, -127, 200, -200 };

    for (int i = 0; i < 4; i++) {
        for (int j = 0; j < 6; j++) {
            emit(vals[i], exps[j]);
        }
    }
}

/* 6. Exponent zero (identity) */
static void test_zero_exponent(void)
{
    float vals[] = {
        0.1f, 0.5f, 1.0f, 1.5f, 2.0f, 10.0f, 100.0f,
        -0.1f, -0.5f, -1.0f, -1.5f, -2.0f, -10.0f, -100.0f,
        FLT_MIN, FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i], 0);
}

