/*
 * nextafter() test harness — prints (x_hex, y_hex, output_hex) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static void emit(double x, double y)
{
    double r = nextafter(x, y);
    printf("%016llx %016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(y), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t x_bits, uint64_t y_bits)
{
    emit(u2d(x_bits), u2d(y_bits));
}

/* 1. Special values */
static void test_special(void)
{
    emit(0.0, 1.0);
    emit(-0.0, 1.0);
    emit(1.0, 0.0);
    emit(1.0, 1.0);
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* qNaN, 1.0 */
    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);  /* sNaN, 1.0 */
    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);  /* -NaN, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0, qNaN */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);  /* +Inf, 1.0 */
}

/* 2. Tiny values (denorms and near-zero) */
static void test_tiny(void)
{
    emit_u(0x0000000000000001ULL, 1.0);  /* min denorm toward 1.0 */
    emit_u(0x800fffffffffffffULL, 1.0);  /* mid denorm */
    emit_u(0x000fffffffffffffULL, 1.0);  /* max denorm toward 1.0 */
    emit(DBL_MIN, 1.0);
    emit(-DBL_MIN, 1.0);
    emit(DBL_MIN, 0.0);
    emit(-DBL_MIN, 0.0);
}

/* 3. Near zero crossing */
static void test_zero_crossing(void)
{
    emit(0.0, 0.5);
    emit(0.0, -0.5);
    emit(-0.0, 0.5);
    emit(-0.0, -0.5);
    emit(0.0, 1.0);
    emit(-0.0, -1.0);
}

/* 4. Moving away from values */
static void test_away(void)
{
    emit(1.0, 2.0);   /* toward 2.0 */
    emit(1.0, 0.0);   /* toward 0.0 */
    emit(2.0, 1.0);   /* backward */
    emit(-1.0, -2.0); /* toward -2.0 */
    emit(-1.0, 0.0);  /* toward 0.0 */
}

/* 5. Boundary values */
static void test_boundaries(void)
{
    emit(DBL_MAX, INFINITY);
    emit(DBL_MAX, 0.0);
    emit(-DBL_MAX, -INFINITY);
    emit(-DBL_MAX, 0.0);
    emit(DBL_MIN, 0.0);
    emit(DBL_MIN, 1.0);
}

/* 6. Repeated stepping */
static void test_repeated_positive(void)
{
    double x = 1.0;
    for (int i = 0; i < 5; i++) {
        x = nextafter(x, 2.0);
        emit(x, 2.0);
    }
}

/* 7. Stepping in both directions */
static void test_bidirectional(void)
{
    emit(0.5, -1.0);
    emit(0.5, 1.0);
    emit(10.0, 5.0);
    emit(10.0, 20.0);
    emit(-0.5, -1.0);
    emit(-0.5, 1.0);
}

/* 8. Sample across range */
static void test_sweep(void)
{
    double vals[] = { 0.0, 0.5, 1.0, 2.0, 10.0, 100.0 };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++) {
        emit(vals[i], vals[i] + 0.1);
        if (vals[i] > 0)
            emit(vals[i], vals[i] - 0.1);
    }
}

/* 9. Random sweep: 15x20 grid = 300 cases */
static void test_random_300(void)
{
    int nx = 15, ny = 20;
    for (int i = 0; i < nx; i++) {
        double x = -5.0 + 10.0 * (double)i / (double)(nx - 1);
        for (int j = 0; j < ny; j++) {
            double y = -5.0 + 10.0 * (double)j / (double)(ny - 1);
            emit(x, y);
        }
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(double x)
{
    volatile double acc = 0.0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += nextafter(x+i, x+i+1.0);
    stopPFM;
    readResult();
    printf("perf %016llx: %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u((double)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(1.0);
#else
    test_special();
    test_tiny();
    test_zero_crossing();
    test_away();
    test_boundaries();
    test_repeated_positive();
    test_bidirectional();
    test_sweep();
    test_random_300();
#endif
    return 0;
}

/*
 * remainder() test harness — prints (x_hex, y_hex, output_hex) triples.
