    emit(2.718281828 - 1.0);        /* log1p(e-1) = 1 */
    emit(-0.5);                     /* log1p(-0.5) = log(0.5) */
    emit(0.5);                      /* log1p(0.5) = log(1.5) */
    emit(9.0);                      /* log1p(9) = log(10) */
    emit(-0.9);                     /* log1p(-0.9) = log(0.1) */
    emit(99.0);                     /* log1p(99) = log(100) */
}

