/*
 * acosh() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly acosh  (test_acosh_opt.elf)
 *   2. Linked with toolchain's default acosh       (test_acosh_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static void emit(double x)
{
    double r = acosh(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* NaN */
    emit_u(0x7ff8000000000000ULL); /* qNaN */
    emit_u(0x7ff0000000000001ULL); /* sNaN */
    emit_u(0xfff8000000000000ULL); /* -NaN */

    /* Infinity */
    emit_u(0x7ff0000000000000ULL); /* +Inf (acosh -> +Inf) */
    emit_u(0xfff0000000000000ULL); /* -Inf (domain error) */
}

/* 2. Tiny values */
static void test_tiny(void)
{
    /* Domain: x >= 1.0 */
    emit_u(0x3ff0000000000000ULL); /* 1.0 exactly */
    emit_u(0x3ff0000000000001ULL); /* 1.0 + eps */
    emit(1.0 + 1.0e-150);
    emit(1.0 + 1.0e-50);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    /* acosh(1) = 0 */
    emit(1.0);

    /* acosh(x) = ln(x + sqrt(x^2 - 1)) */
    emit(2.0);     /* acosh(2) = ln(2 + sqrt(3)) ~ 1.317 */
    emit(3.0);     /* acosh(3) = ln(3 + sqrt(8)) ~ 1.763 */
    emit(4.0);     /* acosh(4) = ln(4 + sqrt(15)) ~ 2.063 */
    emit(5.0);     /* acosh(5) = ln(5 + sqrt(24)) ~ 2.292 */
    emit(10.0);    /* acosh(10) ~ 2.993 */
}

/* 4. Large arguments */
static void test_large(void)
{
    double vals[] = {
        1.0e2, 1.0e4, 1.0e10, 1.0e100, 1.0e300,
        DBL_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Domain boundary behavior */
static void test_boundary(void)
{
    /* Values very close to 1.0 (threshold) */
    double vals[] = {
        1.0,
        1.0 + 1.0e-10,
        1.0 + 1.0e-15,
        1.1,
        1.01,
        1.001,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);

    /* Domain errors (x < 1) */
    emit(0.9);
    emit(0.5);
    emit(0.0);
    emit(-1.0);
}

/* 6. Worst-case rounding */
static void test_hard(void)
{
    double cases[] = {
