#ifdef EN_PERF
static void perf(double x)
{
    volatile long acc = 0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += lrint(x+i);
    stopPFM;
    readResult();
    printf("perf %016llx: %016lx\n",
           (unsigned long long)d2u(x),
           (unsigned long)acc);
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
