    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static void emit(double x, double y)
{
    double r = fmax(x, y);
    printf("%016llx %016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(y), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t x_bits, uint64_t y_bits)
{
    emit(u2d(x_bits), u2d(y_bits));
}

/* 1. Special values */
static void test_special(void)
{
    emit(0.0, 0.0);
    emit(-0.0, 0.0);
    emit(0.0, -0.0);
    emit(-0.0, -0.0);
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* qNaN, 1.0 */
    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);  /* sNaN, 1.0 */
    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);  /* -NaN, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0, qNaN */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);  /* +Inf, 1.0 */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL);  /* -Inf, 1.0 */
}

/* 2. Tiny values (denorms and near-zero) */
static void test_tiny(void)
{
    emit_u(0x0000000000000001ULL, 0x0);  /* min denorm, zero */
    emit_u(0x800fffffffffffffULL, 0x0);  /* mid denorm, zero */
    emit_u(0x000fffffffffffffULL, 0x0);  /* max denorm, zero */
    emit(DBL_MIN, 0.0);
    emit(-DBL_MIN, 0.0);
    emit(1.0e-300, 1.0e-200);
    emit(DBL_MIN, DBL_MIN);
}

/* 3. Equal values */
static void test_equal(void)
{
    emit(1.0, 1.0);
    emit(-1.0, -1.0);
    emit(0.5, 0.5);
    emit(0.0, 0.0);
    emit(3.14159, 3.14159);
    emit(10.0, 10.0);
}

/* 4. Positive asymmetric pairs */
static void test_positive_pairs(void)
{
    emit(1.0, 2.0);
    emit(2.0, 1.0);
    emit(0.5, 1.5);
    emit(10.0, 20.0);
    emit(100.0, 50.0);
}

/* 5. Negative asymmetric pairs */
static void test_negative_pairs(void)
{
    emit(-1.0, -2.0);
    emit(-2.0, -1.0);
    emit(-0.5, -1.5);
    emit(-10.0, -20.0);
    emit(-100.0, -50.0);
}

/* 6. Mixed sign pairs */
static void test_mixed_signs(void)
{
    emit(-1.0, 1.0);
    emit(-2.0, 2.0);
    emit(1.0, -1.0);
    emit(2.0, -2.0);
    emit(-0.5, 0.5);
    emit(0.5, -0.5);
}

/* 7. Large and extreme values */
static void test_large(void)
{
    emit(1.0e100, 1.0e50);
    emit(1.0e300, 1.0e200);
    emit(DBL_MAX, 1.0);
    emit(DBL_MAX, DBL_MAX);
    emit(-DBL_MAX, DBL_MAX);
}

/* 8. Sample across exponent range */
static void test_sweep(void)
{
    double vals[] = { 1e-100, 1e-50, 1e-10, 1.0, 1e10, 1e50, 1e100 };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            emit(vals[i], vals[j]);
            emit(vals[j], vals[i]);
